// Recibe el manifest y produce un item por cada página a generar
const manifest = $input.first().json.body || $input.first().json;

// Validación mínima
if (!manifest.bookId)        throw new Error('manifest.bookId requerido');
if (!manifest.imageSize_px)  throw new Error('manifest.imageSize_px requerido');
if (!manifest.pages)         throw new Error('manifest.pages requerido');

// Routing por defecto si no viene en el manifest
const defaultRouting = {
  'cover-front':       'flux-pro-ultra',
  'cover-back':        'flux-pro-ultra',
  'section-divider':   'flux-pro-ultra',
  'interior-bg-full':  'flux-pro-ultra',
  'interior-bg-soft':  'flux-schnell',
  'decorative-corner': 'flux-schnell'
};
const routing = { ...defaultRouting, ...(manifest.engineRouting || {}) };
const samplesDefault = manifest.samplesPerPage || 1;

// Calcula aspect ratio para Flux Pro Ultra (que solo acepta presets)
function aspectRatio(w, h) {
  const r = w / h;
  const candidates = [
    ['21:9', 21/9], ['16:9', 16/9], ['4:3', 4/3], ['3:2', 3/2],
    ['1:1', 1], ['2:3', 2/3], ['3:4', 3/4], ['9:16', 9/16], ['9:21', 9/21]
  ];
  return candidates.reduce((best, c) =>
    Math.abs(c[1] - r) < Math.abs(best[1] - r) ? c : best
  )[0];
}

const { width, height } = manifest.imageSize_px;
const ar = aspectRatio(width, height);

// Construye prompt con compliance suffix
function buildPrompt(page, manifest) {
  const c = manifest.compliance || {};
  const tags = [];
  if (c.noText)        tags.push('no text', 'no letters', 'no words');
  if (c.noTrademarks)  tags.push('no logos', 'no brand names', 'no copyrighted characters');
  if (c.noFaces)       tags.push('no faces', 'no people');
  if (c.noChildren)    tags.push('no children');
  const styleHint = page.stylePresetOverride || manifest.stylePreset || '';
  return [page.prompt, styleHint, tags.join(', ')].filter(Boolean).join(', ');
}

const items = manifest.pages.map(page => {
  const engine = page.enginePresetOverride || routing[page.type] || 'flux-schnell';
  const samples = Math.min(4, Math.max(1, page.samples || samplesDefault));
  return {
    json: {
      bookId: manifest.bookId,
      n: page.n,
      type: page.type,
      engine,
      samples,
      prompt: buildPrompt(page, manifest),
      negativePrompt: page.negativePrompt || 'low quality, blurry, watermark, signature, jpeg artifacts',
      width,
      height,
      aspectRatio: ar,
      seed: page.seed || null,
      out: page.out || `p${String(page.n).padStart(3, '0')}.png`,
      callback: manifest.callback || null
    }
  };
});

return items;

// Combina la respuesta de fal.ai con los metadatos originales del job
const input = $input.first();
const job = $('Prepare Jobs').itemMatching($input.itemIndex).json;
const response = input.json;

const images = (response.images || []).map((img, i) => ({
  variant: i + 1,
  url: img.url,
  width: img.width,
  height: img.height,
  contentType: img.content_type
}));

return [{
  json: {
    bookId: job.bookId,
    n: job.n,
    type: job.type,
    engine: job.engine,
    out: job.out,
    samplesRequested: job.samples,
    samplesReturned: images.length,
    samples: images,
    seed: response.seed || null,
    success: images.length > 0,
    error: images.length > 0 ? null : (response.error || 'no images returned')
  }
}];
